"use client";
import { useState, useRef } from 'react'; 
import { HfInference } from '@huggingface/inference'; 

export default function ChefInteligenteApp() {
  const tituloApp = "spatula";
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const timerRef = useRef<HTMLHeadingElement>(null);
  const interval = 3000;
  navigator.mediaDevices.getUserMedia({ video: { facingMode: "user" } }).then(stream => { 
    if(videoRef.current) videoRef.current.srcObject = stream; 
    let innterInterval = interval;
    let isPaused = false;
    setInterval(() => {
        if(isPaused && timerRef.current) {
            timerRef.current.innerHTML = 'Procesamiento en pausa' 
        } else if (innterInterval >= 1000 && timerRef.current) {
            timerRef.current.innerHTML =`La próxima captura será tomada dentro de ${innterInterval/1000} segundos`;
            innterInterval -= 1000;
        } else if (timerRef.current) {
            timerRef.current.innerHTML =  'Prediciendo...';
            manejarClickCamara(); 
            innterInterval = interval;
        }
    }, 1000);
})
    .catch(err => { 
        if(timerRef.current) timerRef.current.innerText = "No se pudo acceder a la cámara"; 
    });

  const manejarClickCamara = () => {
    console.log("Abriendo cámara...");
      if (videoRef.current && canvasRef.current) {
        const video = videoRef.current;
        const canvas = canvasRef.current;
        console.log(canvas);
    }
  };

  return (
    <main className="p-6 max-w-md mx-auto bg-gray-50 min-h-screen">
      <h1 className="text-3xl font-bold text-center text-blue-600">
        {tituloApp}
      </h1>
      
      <p className="text-gray-600 text-center mt-2 ">
        Toma una foto a tu refrigerador y te daré opciones de recetas.
      </p>

      <video ref={videoRef} autoPlay playsInline width="400" height="300"></video>
      <canvas ref={canvasRef} style={{ display: 'none' }}></canvas>

      <div className="flex justify-center mt-8">
        <button 
          onClick={manejarClickCamara}
          className="bg-green-500 hover:bg-green-600 text-white font-bold py-3 px-6 rounded-full shadow-lg transition"
        >
          Tomar Foto
        </button>
      </div>
      
      <section className="mt-8 border-t pt-6">
        <h2 className="text-xl font-semibold mb-4">Recetas sugeridas:</h2>
        <div className="bg-white p-4 rounded-lg shadow-sm border text-gray-500 text-center">
          Aún no has subido ninguna foto.
        </div>
      </section>
    </main>
  );
}